-- Supply: Supply and Install [Split Type AC 1.5 Ton Hommer]
INSERT INTO service_inventory (id, service_id, brand_variant_id, link_type, quantity, is_default)
SELECT
  gen_random_uuid(),
  s.id,
  bv.id,
  'supply',
  1,
  TRUE
FROM services s
JOIN inventory_brand_variants bv ON TRUE
JOIN inventory_items ii ON bv.item_id = ii.id
JOIN inventory_categories ic ON ii.category_id = ic.id
