-- SKIP: Shower Filter

-- ============================================================
-- Part B: consumable reclassification
-- ============================================================

-- Consumable: Capacitor - Remove and install a new one [including capacitor cost]
UPDATE service_inventory
SET link_type = 'consumable'
WHERE service_id = (
  SELECT id FROM services
  WHERE name_en = 'Capacitor - Remove and install a new one [including capacitor cost]'
    AND tree_type = 'normal'
  LIMIT 1
);

-- Consumable: Contactor - Remove and install a new one [including contactor cost]
UPDATE service_inventory
SET link_type = 'consumable'
WHERE service_id = (
  SELECT id FROM services
  WHERE name_en = 'Contactor - Remove and install a new one [including contactor cost]'
    AND tree_type = 'normal'
  LIMIT 1
);

-- Consumable: Relay - Remove and install a new one [including relay cost]
UPDATE service_inventory
SET link_type = 'consumable'
WHERE service_id = (
  SELECT id FROM services
  WHERE name_en = 'Relay - Remove and install a new one [including relay cost]'
    AND tree_type = 'normal'
  LIMIT 1
);

-- Consumable: Fan capacitor -- Remove and install a new one [including fan capacitor cost]
UPDATE service_inventory
SET link_type = 'consumable'
WHERE service_id = (
  SELECT id FROM services
  WHERE name_en = 'Fan capacitor -- Remove and install a new one [including fan capacitor cost]'
    AND tree_type = 'normal'
  LIMIT 1
);

-- Consumable: Coil temperature sensor  - Remove and install a new one [including sensor cost]
UPDATE service_inventory
SET link_type = 'consumable'
WHERE service_id = (
  SELECT id FROM services
  WHERE name_en = 'Coil temperature sensor  - Remove and install a new one [including sensor cost]'
    AND tree_type = 'normal'
  LIMIT 1
);

-- Consumable: 3 Phase Contactor - Remove and install a new one [including contactor cost]
UPDATE service_inventory
SET link_type = 'consumable'
WHERE service_id = (
  SELECT id FROM services
  WHERE name_en = '3 Phase Contactor - Remove and install a new one [including contactor cost]'
    AND tree_type = 'normal'
  LIMIT 1
);

-- ============================================================
-- Part C: inventory_categories type update for consumables
-- ============================================================

UPDATE inventory_categories SET type = 'consumables'
WHERE name_en IN (
  'Electrical – Sockets & Switches',
  'Electrical – MCB & ELCB'
);

COMMIT;
